1	<?php
2	declare(strict_types=1);
3	namespace App\Service;
4	
5	use App\Entity\User;
6	use App\Exception\AccessDeniedException;
7	use App\Exception\EntityNotFoundException;
8	use App\Security\OrganizationScope;
9	use App\Security\RbacEnforcer;
10	use Doctrine\ORM\EntityManagerInterface;
11	
12	class BackupService
13	{
14	    private const CIPHER = 'aes-256-cbc';
15	
16	    /**
17	     * Tables that are known to be organisation-scoped.
18	     * Only these are included in backups — prevents SQL errors on system tables
19	     * (doctrine_migration_versions, messenger_messages, etc.) that have no organization_id.
20	     */
21	    private const ORGANISATION_TABLES = [
22	        'audit_logs',
23	        'bills',
24	        'booking_holds',
25	        'bookings',
26	        'inventory_items',
27	        'inventory_pricing',
28	        'ledger_entries',
29	        'notifications',
30	        'payments',
31	        'reconciliation_runs',
32	        'refunds',
33	        'settings',
34	        'terminal_package_transfers',
35	        'terminal_playlists',
36	        'terminals',
37	        'users',
38	    ];
39	
40	    public function __construct(
41	        private readonly EntityManagerInterface $em,
42	        private readonly OrganizationScope $orgScope,
43	        private readonly RbacEnforcer $rbac,
44	        private readonly AuditService $auditService,
45	        private readonly string $backupStoragePath,
46	        private readonly string $backupEncryptionKey,
47	    ) {
48	        if ($this->backupEncryptionKey === '') {
49	            throw new \RuntimeException('BACKUP_ENCRYPTION_KEY environment variable is not set');
50	        }
51	    }
52	
53	    public function createBackup(User $admin): array
54	    {
55	        $this->rbac->enforce($admin, RbacEnforcer::ACTION_MANAGE_BACKUPS);
56	        $orgId = $this->orgScope->getOrganizationId($admin);
57	
58	        return $this->doCreateBackup($orgId, $admin->getUsername());
59	    }
60	
61	    /**
62	     * CLI-only: creates a backup for an organization without requiring an authenticated user.
63	     * Used by CreateBackupCommand for scheduled/automated backups.
64	     */
65	    public function createSystemBackup(string $orgId): array
66	    {
67	        return $this->doCreateBackup($orgId, 'system');
68	    }
69	
70	    private function doCreateBackup(string $orgId, string $actorUsername): array
71	    {
72	        $timestamp = (new \DateTimeImmutable())->format('Ymd_His');
73	        $filename = sprintf('backup_%s_%s.enc', $orgId, $timestamp);
74	        $filepath = rtrim($this->backupStoragePath, '/') . '/' . $filename;
75	
76	        if (!is_dir($this->backupStoragePath)) {
77	            mkdir($this->backupStoragePath, 0750, true);
78	        }
79	
80	        $connection = $this->em->getConnection();
81	
82	        // Only back up tables that exist in this schema AND are organisation-scoped.
83	        $existingTables = $connection->createSchemaManager()->listTableNames();
84	        $tables = array_values(array_intersect(self::ORGANISATION_TABLES, $existingTables));
85	
86	        $dumpData = [
87	            'metadata' => [
88	                'organization_id' => $orgId,
89	                'created_at' => (new \DateTimeImmutable())->format(\DateTimeInterface::ATOM),
90	                'created_by' => $actorUsername,
91	                'tables' => $tables,
92	            ],
93	            'data' => [],
94	        ];
95	
96	        foreach ($tables as $table) {
97	            $rows = $connection->fetchAllAssociative(
98	                sprintf('SELECT * FROM %s WHERE organization_id = :orgId', $connection->quoteIdentifier($table)),
99	                ['orgId' => $orgId],
100	            );
101	            if (!empty($rows)) {
102	                $dumpData['data'][$table] = $rows;
103	            }
104	        }
105	
106	        $jsonPayload = json_encode($dumpData, JSON_THROW_ON_ERROR | JSON_PRETTY_PRINT);
107	        $encrypted = $this->encrypt($jsonPayload);
108	
109	        file_put_contents($filepath, $encrypted);
110	
111	        $this->auditService->log(
112	            $orgId,
113	            null,
114	            $actorUsername,
115	            'BACKUP_CREATED',
116	            'Backup',
117	            $filename,
118	            null,
119	            ['filename' => $filename, 'tables' => $tables],
120	        );
121	
122	        return [
123	            'filename' => $filename,
124	            'created_at' => $dumpData['metadata']['created_at'],
125	            'tables' => $tables,
126	        ];
127	    }
128	
129	    public function listBackups(User $admin, int $page = 1, int $perPage = 25): array
130	    {
131	        $this->rbac->enforce($admin, RbacEnforcer::ACTION_MANAGE_BACKUPS);
132	        $orgId = $this->orgScope->getOrganizationId($admin);
133	
134	        $backups = [];
135	        $pattern = rtrim($this->backupStoragePath, '/') . '/backup_' . $orgId . '_*.enc';
136	        $files = glob($pattern);
137	
138	        if ($files === false) {
139	            return [];
140	        }
141	
142	        foreach ($files as $file) {
143	            $backups[] = [
144	                'filename' => basename($file),
145	                'size_bytes' => filesize($file),
146	                'modified_at' => (new \DateTimeImmutable('@' . filemtime($file)))->format(\DateTimeInterface::ATOM),
147	            ];
148	        }
149	
150	        usort($backups, fn(array $a, array $b) => $b['modified_at'] <=> $a['modified_at']);
151	
152	        $offset = ($page - 1) * $perPage;
153	
154	        return array_slice($backups, $offset, $perPage);
155	    }
156	
157	    public function previewRestore(User $admin, string $filename): array
158	    {
159	        $this->rbac->enforce($admin, RbacEnforcer::ACTION_MANAGE_BACKUPS);
160	        $orgId = $this->orgScope->getOrganizationId($admin);
161	
162	        $filepath = $this->resolveBackupPath($filename, $orgId);
163	
164	        $encrypted = file_get_contents($filepath);
165	        if ($encrypted === false) {
166	            throw new EntityNotFoundException('Backup', $filename);
167	        }
168	
169	        $data = $this->decryptAndDecode($encrypted);
170	
171	        if ($data['metadata']['organization_id'] !== $orgId) {
172	            throw new AccessDeniedException();
173	        }
174	
175	        $tableCounts = [];
176	        foreach ($data['data'] as $table => $rows) {
177	            $tableCounts[$table] = count($rows);
178	        }
179	
180	        return [
181	            'metadata' => $data['metadata'],
182	            'record_counts' => $tableCounts,
183	        ];
184	    }
185	
186	    public function restore(User $admin, string $filename): array
187	    {
188	        $this->rbac->enforce($admin, RbacEnforcer::ACTION_MANAGE_BACKUPS);
189	        $orgId = $this->orgScope->getOrganizationId($admin);
190	
191	        $filepath = $this->resolveBackupPath($filename, $orgId);
192	
193	        $encrypted = file_get_contents($filepath);
194	        if ($encrypted === false) {
195	            throw new EntityNotFoundException('Backup', $filename);
196	        }
197	
198	        $data = $this->decryptAndDecode($encrypted);
199	
200	        if ($data['metadata']['organization_id'] !== $orgId) {
201	            throw new AccessDeniedException();
202	        }
203	
204	        // Validate that all tables in the backup are on the allow-list.
205	        $invalidTables = array_diff(array_keys($data['data']), self::ORGANISATION_TABLES);
206	        if (!empty($invalidTables)) {
207	            throw new \RuntimeException('Backup contains unexpected tables: ' . implode(', ', $invalidTables));
208	        }
209	
210	        $connection = $this->em->getConnection();
211	        $restoredCounts = [];
212	
213	        $connection->beginTransaction();
214	        try {
215	            foreach ($data['data'] as $table => $rows) {
216	                $connection->executeStatement(
217	                    sprintf('DELETE FROM %s WHERE organization_id = :orgId', $connection->quoteIdentifier($table)),
218	                    ['orgId' => $orgId],
219	                );
220	
221	                foreach ($rows as $row) {
222	                    $connection->insert($table, $row);
223	                }
224	
225	                $restoredCounts[$table] = count($rows);
226	            }
227	            $connection->commit();
228	        } catch (\Throwable $e) {
229	            $connection->rollBack();
230	            throw $e;
231	        }
232	
233	        $this->auditService->log(
234	            $orgId,
235	            $admin,
236	            $admin->getUsername(),
237	            'BACKUP_RESTORED',
238	            'Backup',
239	            $filename,
240	            null,
241	            ['filename' => $filename, 'restored_counts' => $restoredCounts],
242	        );
243	
244	        return [
245	            'filename' => $filename,
246	            'restored_at' => (new \DateTimeImmutable())->format(\DateTimeInterface::ATOM),
247	            'restored_counts' => $restoredCounts,
248	        ];
249	    }
250	
251	    /**
252	     * Resolve a backup filename to a full path, preventing path traversal attacks.
253	     * Only allows filenames matching the pattern: backup_{orgId}_{timestamp}.enc
254	     */
255	    private function resolveBackupPath(string $filename, string $orgId): string
256	    {
257	        // Strip any directory components — only a bare filename is allowed.
258	        $safe = basename($filename);
259	
260	        // Enforce expected filename format to prevent arbitrary file access.
261	        if (!preg_match('/^backup_[a-zA-Z0-9\-]+_\d{8}_\d{6}\.enc$/', $safe)) {
262	            throw new \InvalidArgumentException('Invalid backup filename format');
263	        }
264	
265	        $filepath = rtrim($this->backupStoragePath, '/') . '/' . $safe;
266	
267	        if (!file_exists($filepath)) {
268	            throw new EntityNotFoundException('Backup', $safe);
269	        }
270	
271	        // Confirm the resolved path is still inside the storage directory (realpath check).
272	        $realStorage = realpath($this->backupStoragePath);
273	        $realFile = realpath($filepath);
274	        if ($realStorage === false || $realFile === false || !str_starts_with($realFile, $realStorage . DIRECTORY_SEPARATOR)) {
275	            throw new \InvalidArgumentException('Backup file path is outside storage directory');
276	        }
277	
278	        return $filepath;
279	    }
280	
281	    private function decryptAndDecode(string $encoded): array
282	    {
283	        $json = $this->decrypt($encoded);
284	        return json_decode($json, true, 512, JSON_THROW_ON_ERROR);
285	    }
286	
287	    private function encrypt(string $plaintext): string
288	    {
289	        $ivLength = openssl_cipher_iv_length(self::CIPHER);
290	        if ($ivLength === false) {
291	            throw new \RuntimeException('Failed to determine IV length for cipher');
292	        }
293	
294	        $iv = openssl_random_pseudo_bytes($ivLength);
295	        $ciphertext = openssl_encrypt($plaintext, self::CIPHER, $this->backupEncryptionKey, OPENSSL_RAW_DATA, $iv);
296	
297	        if ($ciphertext === false) {
298	            throw new \RuntimeException('Encryption failed');
299	        }
300	
301	        $hmac = hash_hmac('sha256', $iv . $ciphertext, $this->backupEncryptionKey, true);
302	
303	        return base64_encode($hmac . $iv . $ciphertext);
304	    }
305	
306	    private function decrypt(string $encoded): string
307	    {
308	        $raw = base64_decode($encoded, true);
309	        if ($raw === false) {
310	            throw new \RuntimeException('Invalid backup file encoding');
311	        }
312	
313	        $hmacLength = 32; // SHA-256 = 32 bytes
314	        $ivLength = openssl_cipher_iv_length(self::CIPHER);
315	        if ($ivLength === false) {
316	            throw new \RuntimeException('Failed to determine IV length for cipher');
317	        }
318	
319	        if (strlen($raw) < $hmacLength + $ivLength) {
320	            throw new \RuntimeException('Backup file is too short — likely corrupted');
321	        }
322	
323	        $hmac = substr($raw, 0, $hmacLength);
324	        $iv = substr($raw, $hmacLength, $ivLength);
325	        $ciphertext = substr($raw, $hmacLength + $ivLength);
326	
327	        // Verify integrity before decrypting (timing-safe comparison).
328	        $expectedHmac = hash_hmac('sha256', $iv . $ciphertext, $this->backupEncryptionKey, true);
329	        if (!hash_equals($expectedHmac, $hmac)) {
330	            throw new \RuntimeException('Backup integrity check failed — invalid key or corrupted data');
331	        }
332	
333	        $plaintext = openssl_decrypt($ciphertext, self::CIPHER, $this->backupEncryptionKey, OPENSSL_RAW_DATA, $iv);
334	
335	        if ($plaintext === false) {
336	            throw new \RuntimeException('Decryption failed');
337	        }
338	
339	        return $plaintext;
340	    }
341	}
