265	    // ─── encryption integrity ─────────────────────────────────────────────
266	
267	    public function testCorruptedBackupThrowsOnRestore(): void
268	    {
269	        $admin = $this->makeUser(UserRole::ADMINISTRATOR);
270	        $service = $this->makeService();
271	
272	        $backup = $service->createBackup($admin);
273	        $filepath = $this->tmpDir . '/' . $backup['filename'];
274	
275	        // Corrupt the file.
