27	class PaymentService
28	{
29	    public function __construct(
30	        private readonly PaymentRepository $paymentRepository,
31	        private readonly BillRepository $billRepository,
32	        private readonly SettingsRepository $settingsRepository,
33	        private readonly LedgerService $ledgerService,
34	        private readonly BillingService $billingService,
35	        private readonly PaymentSignatureVerifier $signatureVerifier,
36	        private readonly OrganizationScope $orgScope,
37	        private readonly RbacEnforcer $rbac,
38	        private readonly AuditService $auditService,
39	        private readonly NotificationService $notificationService,
40	        private readonly EntityManagerInterface $em,
41	    ) {}
42	
43	    public function initiatePayment(User $tenant, string $billId, string $amount, string $currency): Payment
44	    {
45	        if ($tenant->getRole() !== UserRole::TENANT) {
46	            throw new AccessDeniedException('Only tenants can initiate payments');
47	        }
48	
49	        if (!is_numeric($amount) || bccomp($amount, '0.00', 2) <= 0) {
50	            throw new PaymentValidationException('Payment amount must be greater than zero');
51	        }
52	
53	        if (trim($currency) === '' || strlen($currency) !== 3) {
54	            throw new PaymentValidationException('Currency must be a valid 3-character code');
55	        }
56	
57	        $orgId = $this->orgScope->getOrganizationId($tenant);
58	
59	        // Lock the bill row to prevent concurrent payments from exceeding outstanding amount
60	        $conn = $this->em->getConnection();
61	        $conn->beginTransaction();
62	
63	        try {
64	            // Acquire exclusive lock on the bill
65	            $row = $conn->fetchAssociative(
66	                'SELECT id, status, outstanding_amount, currency, tenant_user_id FROM bills WHERE id = ? AND organization_id = ? FOR UPDATE',
67	                [$billId, $orgId],
68	            );
69	
70	            if ($row === false) {
71	                $conn->rollBack();
72	                throw new EntityNotFoundException('Bill', $billId);
73	            }
74	
75	            if ($row['tenant_user_id'] !== $tenant->getId()) {
76	                $conn->rollBack();
77	                throw new AccessDeniedException('Bill does not belong to this tenant');
78	            }
79	
80	            $billStatus = $row['status'];
81	            if ($billStatus !== 'open' && $billStatus !== 'partially_paid') {
82	                $conn->rollBack();
83	                throw new PaymentValidationException('Bill is not in a payable status');
84	            }
85	
86	            if ($currency !== $row['currency']) {
87	                $conn->rollBack();
88	                throw new CurrencyMismatchException();
89	            }
90	
91	            $outstanding = $row['outstanding_amount'];
92	
93	            // Deduct PENDING payments already in flight to prevent sequential overpayment.
94	            // This query runs inside the bill FOR UPDATE lock, so no new payments can be
95	            // inserted concurrently for this bill.
96	            $pendingTotal = $conn->fetchOne(
97	                'SELECT COALESCE(SUM(amount), 0) FROM payments WHERE bill_id = ? AND status = ?',
98	                [$billId, 'pending'],
99	            );
100	            $effectiveOutstanding = bcsub($outstanding, (string) $pendingTotal, 2);
101	
102	            if (bccomp($effectiveOutstanding, '0.00', 2) <= 0) {
103	                $conn->rollBack();
104	                throw new PaymentValidationException('A payment is already pending for this bill');
105	            }
106	
107	            $settings = $this->settingsRepository->findByOrganizationId($orgId);
108	            $allowPartial = $settings !== null ? $settings->getAllowPartialPayments() : false;
109	
110	            if (!$allowPartial) {
111	                if (bccomp($amount, $effectiveOutstanding, 2) !== 0) {
112	                    $conn->rollBack();
113	                    throw new PaymentValidationException('Partial payments are not allowed; amount must equal outstanding balance');
114	                }
115	            } else {
116	                if (bccomp($amount, $effectiveOutstanding, 2) > 0) {
117	                    $conn->rollBack();
118	                    throw new PaymentValidationException('Payment amount exceeds available balance');
119	                }
120	            }
121	
122	            // Refresh the bill entity inside the lock scope
123	            $bill = $this->billRepository->findByIdAndOrg($billId, $orgId);
124	            $requestId = Uuid::v4()->toRfc4122();
125	
126	            $payment = new Payment(
127	                Uuid::v4()->toRfc4122(),
128	                $bill->getOrganization(),
129	                $bill,
130	                $requestId,
131	                $currency,
132	                $amount,
133	            );
134	
135	            $this->em->persist($payment);
136	            $this->em->flush();
137	            $conn->commit();
138	        } catch (\Throwable $e) {
139	            if ($conn->isTransactionActive()) {
140	                $conn->rollBack();
141	            }
142	            throw $e;
143	        }
144	
145	        $this->auditService->log(
146	            $orgId,
147	            $tenant,
148	            $tenant->getUsername(),
149	            AuditActions::PAYMENT_INITIATED,
150	            'Payment',
151	            $payment->getId(),
152	            null,
153	            ['bill_id' => $billId, 'amount' => $amount, 'currency' => $currency, 'request_id' => $requestId],
154	        );
155	
156	        return $payment;
157	    }
158	
159	    public function processCallback(string $requestId, string $signature, array $payload): Payment
160	    {
161	        $this->em->beginTransaction();
162	
163	        try {
164	            // Row-level lock to prevent concurrent callback processing
165	            $conn = $this->em->getConnection();
166	            $row = $conn->fetchAssociative(
167	                'SELECT id, status FROM payments WHERE request_id = ? FOR UPDATE',
168	                [$requestId],
169	            );
170	
171	            if ($row === false) {
172	                $this->em->rollback();
173	                throw new EntityNotFoundException('Payment', $requestId);
174	            }
175	
176	            // Idempotency: if already terminal, return existing result without reprocessing
177	            $currentStatus = PaymentStatus::from($row['status']);
178	            if ($currentStatus->isTerminal()) {
179	                $this->em->rollback();
180	                $payment = $this->paymentRepository->findByRequestId($requestId);
181	                return $payment;
182	            }
183	
184	            $payment = $this->paymentRepository->findByRequestId($requestId);
185	
186	            if (!$this->signatureVerifier->verifySignature($signature, $payload)) {
187	                $this->em->rollback();
188	                throw new PaymentValidationException('Invalid payment signature');
189	            }
190	
191	            $payment->setSignatureVerified(true);
192	            $payment->setRawCallbackPayloadJson($payload);
193	
194	            $callbackAmount = (string) ($payload['amount'] ?? '0.00');
195	            $callbackCurrency = (string) ($payload['currency'] ?? '');
196	
197	            if (bccomp($callbackAmount, $payment->getAmount(), 2) !== 0) {
198	                $this->em->rollback();
199	                throw new PaymentValidationException('Callback amount does not match payment amount');
200	            }
201	
202	            if ($callbackCurrency !== $payment->getCurrency()) {
203	                $this->em->rollback();
204	                throw new PaymentValidationException('Callback currency does not match payment currency');
205	            }
206	
207	            $callbackStatus = (string) ($payload['status'] ?? '');
208	            $externalReference = (string) ($payload['external_reference'] ?? '');
209	
210	            if ($externalReference !== '') {
211	                $payment->setExternalReference($externalReference);
212	            }
213	
214	            if ($callbackStatus === 'succeeded' || $callbackStatus === 'success') {
215	                $bill = $payment->getBill();
216	
217	                // Re-check: would this payment cause overpayment?
218	                // Sum all already-SUCCEEDED payments for this bill.
219	                $alreadyPaid = (string) $conn->fetchOne(
220	                    'SELECT COALESCE(SUM(amount), 0) FROM payments WHERE bill_id = ? AND status = ?',
221	                    [$bill->getId(), 'succeeded'],
222	                );
223	                $alreadyRefunded = (string) $conn->fetchOne(
224	                    'SELECT COALESCE(SUM(amount), 0) FROM refunds WHERE bill_id = ? AND status = ?',
225	                    [$bill->getId(), 'issued'],
226	                );
227	                $netPaid = bcsub($alreadyPaid, $alreadyRefunded, 2);
228	                $wouldBePaid = bcadd($netPaid, $payment->getAmount(), 2);
229	
230	                if (bccomp($wouldBePaid, $bill->getOriginalAmount(), 2) > 0) {
231	                    // This payment would exceed the bill total — reject it
232	                    $payment->transitionTo(PaymentStatus::REJECTED);
233	                    $this->em->flush();
234	                    $this->em->commit();
235	
236	                    return $payment;
237	                }
238	
239	                $payment->transitionTo(PaymentStatus::SUCCEEDED);
240	
241	                $this->billingService->updateBillStatus($bill);
242	
243	                $this->ledgerService->createEntry(
244	                    $payment->getOrganizationId(),
245	                    LedgerEntryType::PAYMENT_RECEIVED,
246	                    $payment->getAmount(),
247	                    $payment->getCurrency(),
248	                    $bill->getBookingId(),
249	                    $bill->getId(),
250	                    $payment->getId(),
251	                );
252	            } elseif ($callbackStatus === 'rejected') {
253	                $payment->transitionTo(PaymentStatus::REJECTED);
254	            } else {
255	                $payment->transitionTo(PaymentStatus::FAILED);
256	            }
257	
258	            $this->em->flush();
259	            $this->em->commit();
260	        } catch (\Throwable $e) {
261	            if ($this->em->getConnection()->isTransactionActive()) {
262	                $this->em->rollback();
263	            }
264	            throw $e;
265	        }
266	
267	        // Post-commit: audit and notification are fire-and-forget
268	        try {
269	            $this->auditService->log(
270	                $payment->getOrganizationId(),
271	                null,
272	                'payment_callback',
273	                AuditActions::PAYMENT_CALLBACK_PROCESSED,
274	                'Payment',
275	                $payment->getId(),
276	                ['status' => PaymentStatus::PENDING->value],
277	                ['status' => $payment->getStatus()->value],
278	            );
279	        } catch (\Throwable) {
280	            // Audit failure does not undo committed payment
281	        }
282	
283	        try {
284	            if ($payment->getStatus() === PaymentStatus::SUCCEEDED) {
285	                $bill = $payment->getBill();
286	                $this->notificationService->createNotification($payment->getOrganizationId(), $bill->getTenantUserId(), 'payment.received', 'Payment Received', 'Your payment of ' . $payment->getAmount() . ' ' . $payment->getCurrency() . ' has been received.');
287	            }
288	        } catch (\Throwable) {
289	            // Notification failure is tolerated — payment is already committed
290	        }
291	
292	        return $payment;
293	    }
294	
295	    public function getPayment(User $user, string $paymentId): Payment
296	    {
297	        $orgId = $this->orgScope->getOrganizationId($user);
298	        $payment = $this->paymentRepository->findByIdAndOrg($paymentId, $orgId);
299	
300	        if ($payment === null) {
301	            throw new EntityNotFoundException('Payment', $paymentId);
302	        }
303	
304	        if ($user->getRole() === UserRole::TENANT) {
305	            $bill = $payment->getBill();
306	            if ($bill->getTenantUserId() !== $user->getId()) {
307	                throw new AccessDeniedException('Payment does not belong to this tenant');
308	            }
309	        }
310	
311	        return $payment;
312	    }
313	
314	    public function listPayments(User $user, array $filters, int $page, int $perPage): array
315	    {
316	        $orgId = $this->orgScope->getOrganizationId($user);
317	        $perPage = min($perPage, 100);
318	
319	        if ($user->getRole() === UserRole::TENANT) {
320	            $filters['tenant_user_id'] = $user->getId();
321	        }
322	
323	        $items = $this->paymentRepository->findByOrg($orgId, $filters, $page, $perPage);
324	        $total = $this->paymentRepository->countByOrg($orgId, $filters);
325	
326	        return [
327	            'data' => $items,
328	            'meta' => [
329	                'page' => $page,
330	                'per_page' => $perPage,
331	                'total' => $total,
332	                'has_next' => ($page * $perPage) < $total,
333	            ],
334	        ];
335	    }
336	}
