8	/**
9	 * DB-backed throttle service. Uses a lightweight query against booking_holds
10	 * to count recent attempts per inventory item within a 60-second window.
11	 * Survives process restarts and works across multiple workers.
12	 */
13	class ThrottleService
14	{
15	    private int $defaultLimit = 30;
16	
17	    public function __construct(
18	        private readonly Connection $connection,
19	    ) {}
20	
21	    public function checkAndRecord(string $inventoryItemId, int $limit = 0): void
22	    {
23	        $effectiveLimit = $limit > 0 ? $limit : $this->defaultLimit;
24	        $windowStart = (new \DateTimeImmutable('-60 seconds'))->format('Y-m-d H:i:s');
25	
26	        // Count recent hold creation attempts for this item (proxy for booking attempts)
27	        $recentAttempts = (int) $this->connection->fetchOne(
28	            'SELECT COUNT(*) FROM booking_holds WHERE inventory_item_id = ? AND created_at >= ?',
29	            [$inventoryItemId, $windowStart],
30	        );
31	
32	        if ($recentAttempts >= $effectiveLimit) {
33	            throw new ThrottleLimitException();
34	        }
35	    }
36	}
