30	class BookingHoldService
31	{
32	    public function __construct(
33	        private readonly BookingHoldRepository $holdRepository,
34	        private readonly InventoryItemRepository $inventoryItemRepository,
35	        private readonly PricingService $pricingService,
36	        private readonly IdempotencyService $idempotencyService,
37	        private readonly ThrottleService $throttleService,
38	        private readonly SettingsRepository $settingsRepository,
39	        private readonly BillingService $billingService,
40	        private readonly LedgerService $ledgerService,
41	        private readonly AuditService $auditService,
42	        private readonly NotificationService $notificationService,
43	        private readonly OrganizationScope $orgScope,
44	        private readonly EntityManagerInterface $em,
45	    ) {}
