47	    public function createHold(
48	        User $tenant,
49	        string $inventoryItemId,
50	        int $units,
51	        \DateTimeImmutable $startAt,
52	        \DateTimeImmutable $endAt,
53	        string $requestKey,
54	    ): BookingHold {
55	        if ($tenant->getRole() !== UserRole::TENANT) {
56	            throw new AccessDeniedException('Only tenants can create holds');
57	        }
58	
59	        $existing = $this->idempotencyService->check($tenant->getId(), $requestKey);
60	        if ($existing !== null) {
61	            throw new DuplicateRequestException($existing);
62	        }
63	
64	        $orgId = $this->orgScope->getOrganizationId($tenant);
65	        $settings = $this->settingsRepository->findByOrganizationId($orgId);
66	
67	        $item = $this->inventoryItemRepository->findByIdAndOrg($inventoryItemId, $orgId);
68	        if ($item === null) {
69	            throw new EntityNotFoundException('InventoryItem', $inventoryItemId);
70	        }
71	
72	        if (!$item->isActive()) {
73	            throw new \DomainException('Inventory item is not active');
74	        }
75	
76	        $maxDays = $settings !== null ? $settings->getMaxBookingDurationDays() : 365;
77	        $durationDays = $startAt->diff($endAt)->days;
78	        if ($durationDays > $maxDays) {
79	            throw new BookingDurationExceededException();
80	        }
81	
82	        $holdDuration = $settings !== null ? $settings->getHoldDurationMinutes() : 10;
83	        $throttleLimit = $settings !== null ? $settings->getBookingAttemptsPerItemPerMinute() : 30;
84	
85	        // ATOMIC: throttle + lock + validate capacity + create hold in single transaction
86	        $hold = $this->em->wrapInTransaction(function () use ($tenant, $item, $inventoryItemId, $units, $startAt, $endAt, $requestKey, $holdDuration, $throttleLimit) {
87	            $conn = $this->em->getConnection();
88	            $conn->executeStatement(
89	                'SELECT id FROM inventory_items WHERE id = ? FOR UPDATE',
90	                [$inventoryItemId]
91	            );
92	
93	            // Throttle check INSIDE transaction, after row lock — fully atomic
94	            $this->throttleService->checkAndRecord($inventoryItemId, $throttleLimit);
95	
96	            $activeHeldUnits = (int) $conn->fetchOne(
97	                'SELECT COALESCE(SUM(held_units), 0) FROM booking_holds WHERE inventory_item_id = ? AND status = ? AND start_at < ? AND end_at > ?',
98	                [$inventoryItemId, BookingHoldStatus::ACTIVE->value, $endAt->format('Y-m-d H:i:s'), $startAt->format('Y-m-d H:i:s')]
99	            );
100	
101	            $activeBookedUnits = (int) $conn->fetchOne(
102	                'SELECT COALESCE(SUM(booked_units), 0) FROM bookings WHERE inventory_item_id = ? AND status IN (?, ?) AND start_at < ? AND end_at > ?',
103	                [$inventoryItemId, BookingStatus::CONFIRMED->value, BookingStatus::ACTIVE->value, $endAt->format('Y-m-d H:i:s'), $startAt->format('Y-m-d H:i:s')]
104	            );
105	
106	            $available = $item->getTotalCapacity() - $activeHeldUnits - $activeBookedUnits;
107	
108	            if ($units > $available) {
109	                throw new InsufficientCapacityException();
110	            }
111	
112	            $expiresAt = new \DateTimeImmutable("+{$holdDuration} minutes");
113	
114	            $newHold = new BookingHold(
115	                Uuid::v4()->toRfc4122(),
116	                $tenant->getOrganization(),
117	                $item,
118	                $tenant,
119	                $requestKey,
120	                $units,
121	                $startAt,
122	                $endAt,
123	                $expiresAt,
124	            );
125	
126	            $this->em->persist($newHold);
127	            return $newHold;
128	        });
129	
130	        $this->idempotencyService->store($tenant, $requestKey, ['hold_id' => $hold->getId()]);
131	
132	        $this->auditService->log(
133	            $orgId,
134	            $tenant,
135	            $tenant->getUsername(),
136	            AuditActions::HOLD_CREATED,
137	            'BookingHold',
138	            $hold->getId(),
139	            null,
140	            [
141	                'inventory_item_id' => $inventoryItemId,
142	                'units' => $units,
143	                'start_at' => $startAt->format('c'),
144	                'end_at' => $endAt->format('c'),
145	                'expires_at' => $hold->getExpiresAt()->format('c'),
146	            ],
147	        );
148	
149	        return $hold;
150	    }
