152	    public function confirmHold(User $tenant, string $holdId, string $requestKey): Booking
153	    {
154	        $existing = $this->idempotencyService->check($tenant->getId(), $requestKey);
155	        if ($existing !== null) {
156	            throw new DuplicateRequestException($existing);
157	        }
158	
159	        $orgId = $this->orgScope->getOrganizationId($tenant);
160	
161	        // Wrap in transaction with row-level lock to prevent concurrent double-confirm.
162	        $booking = $this->em->wrapInTransaction(function () use ($tenant, $holdId, $orgId, $requestKey) {
163	            $conn = $this->em->getConnection();
164	
165	            // Acquire exclusive lock on the hold row — a concurrent confirm will block here.
166	            $row = $conn->fetchAssociative(
167	                'SELECT id, status, expires_at, tenant_user_id FROM booking_holds WHERE id = ? AND organization_id = ? FOR UPDATE',
168	                [$holdId, $orgId],
169	            );
170	
171	            if ($row === false) {
172	                throw new EntityNotFoundException('BookingHold', $holdId);
173	            }
174	
175	            if ($row['tenant_user_id'] !== $tenant->getId()) {
176	                throw new AccessDeniedException('Hold does not belong to this tenant');
177	            }
178	
179	            if ($row['status'] !== 'active') {
180	                throw new \DomainException('Hold is not active');
181	            }
182	
183	            $expiresAt = new \DateTimeImmutable($row['expires_at']);
184	            if ($expiresAt < new \DateTimeImmutable()) {
185	                throw new HoldExpiredException();
186	            }
187	
188	            // Re-fetch the managed entity now that we hold the lock.
189	            $hold = $this->holdRepository->findByIdAndOrg($holdId, $orgId);
190	            $hold->transitionTo(BookingHoldStatus::CONVERTED);
191	
192	            $amount = $this->pricingService->calculateBookingAmount(
193	                $hold->getInventoryItemId(),
194	                $hold->getStartAt(),
195	                $hold->getEndAt(),
196	                $hold->getHeldUnits(),
197	            );
198	
199	            $currency = $hold->getOrganization()->getDefaultCurrency();
200	
201	            $bookingId = Uuid::v4()->toRfc4122();
202	            $booking = new Booking(
203	                $bookingId,
204	                $hold->getOrganization(),
205	                $hold->getInventoryItem(),
206	                $tenant,
207	                $hold,
208	                $hold->getStartAt(),
209	                $hold->getEndAt(),
210	                $hold->getHeldUnits(),
211	                $currency,
212	                $amount,
213	                $amount,
214	            );
215	
216	            $hold->setConfirmedBookingId($bookingId);
217	
218	            $this->em->persist($booking);
219	
220	            // issueInitialBill creates the bill AND its BILL_ISSUED ledger entry atomically.
221	            // No additional ledger write here — single source of truth is BillingService.
222	            $this->billingService->issueInitialBill($tenant, $booking);
223	
224	            $event = new BookingEvent(
225	                Uuid::v4()->toRfc4122(),
226	                $booking,
227	                $tenant,
228	                BookingEventType::HOLD_CONVERTED,
229	                null,
230	                BookingStatus::CONFIRMED,
231	                ['hold_id' => $holdId],
232	            );
233	            $this->em->persist($event);
234	
235	            $this->idempotencyService->store($tenant, $requestKey, ['booking_id' => $booking->getId()]);
236	
237	            return $booking;
238	        });
239	
240	        // Post-commit: fire-and-forget audit + notification (failures don't undo the booking)
241	        try {
242	            $this->auditService->log(
243	                $orgId,
244	                $tenant,
245	                $tenant->getUsername(),
246	                AuditActions::HOLD_CONFIRMED,
247	                'BookingHold',
248	                $holdId,
249	                null,
250	                ['booking_id' => $booking->getId(), 'amount' => $booking->getFinalAmount()],
251	            );
252	        } catch (\Throwable) {}
253	
254	        try {
255	            $this->notificationService->createNotification(
256	                $orgId,
257	                $tenant->getId(),
258	                'booking.confirmed',
259	                'Booking Confirmed',
260	                'Your booking has been confirmed for ' . $booking->getStartAt()->format('Y-m-d H:i'),
261	            );
262	        } catch (\Throwable) {}
263	
264	        return $booking;
265	    }
266	
267	    public function releaseHold(User $user, string $holdId): void
268	    {
269	        $orgId = $this->orgScope->getOrganizationId($user);
270	        $hold = $this->holdRepository->findByIdAndOrg($holdId, $orgId);
271	
272	        if ($hold === null) {
273	            throw new EntityNotFoundException('BookingHold', $holdId);
274	        }
275	
276	        // Tenant users may only release their own holds
277	        if ($user->getRole() === UserRole::TENANT && $hold->getTenantUserId() !== $user->getId()) {
278	            throw new AccessDeniedException('Hold does not belong to this tenant');
279	        }
280	
281	        if ($hold->getStatus() !== BookingHoldStatus::ACTIVE) {
282	            throw new \DomainException('Hold is not active');
283	        }
284	
285	        $hold->transitionTo(BookingHoldStatus::RELEASED);
286	        $this->em->flush();
287	
288	        $this->auditService->log(
289	            $orgId,
290	            $user,
291	            $user->getUsername(),
292	            AuditActions::HOLD_RELEASED,
293	            'BookingHold',
294	            $holdId,
295	        );
296	    }
297	
298	    public function expireHolds(): int
299	    {
300	        $expiredHolds = $this->holdRepository->findExpiredActive();
301	        $count = 0;
302	
303	        foreach ($expiredHolds as $hold) {
304	            try {
305	                $this->em->wrapInTransaction(function () use ($hold) {
306	                    $hold->transitionTo(BookingHoldStatus::EXPIRED);
307	                    $this->em->flush();
308	                });
309	                $count++;
310	            } catch (\Throwable) {
311	                // Per-hold isolation: failure on one hold does not halt others
312	                continue;
313	            }
314	        }
315	
316	        return $count;
317	    }
318	
319	    public function getHold(User $user, string $holdId): BookingHold
320	    {
321	        $orgId = $this->orgScope->getOrganizationId($user);
322	        $hold = $this->holdRepository->findByIdAndOrg($holdId, $orgId);
323	
324	        if ($hold === null) {
325	            throw new EntityNotFoundException('BookingHold', $holdId);
326	        }
327	
328	        if ($user->getRole() === UserRole::TENANT && $hold->getTenantUserId() !== $user->getId()) {
329	            throw new AccessDeniedException('Hold does not belong to this tenant');
330	        }
331	
332	        return $hold;
333	    }
334	}
