68	    public function enforce(User $user, string $action, ?string $resourceOwnerId = null): void
69	    {
70	        $role = $user->getRole()->value;
71	        $allowedActions = self::ROLE_PERMISSIONS[$role] ?? [];
72	
73	        if (!in_array($action, $allowedActions, true)) {
74	            throw new AccessDeniedException();
75	        }
