declare(strict_types=1);

namespace App\Command;

use App\Service\BackupService;
use App\Service\BillingService;
use App\Service\BookingHoldService;
use App\Service\BookingService;
use App\Service\IdempotencyService;
use App\Service\NotificationService;
use App\Service\ReconciliationService;
use App\Repository\UserRepository;
use Symfony\Component\Console\Attribute\AsCommand;
use Symfony\Component\Console\Command\Command;
use Symfony\Component\Console\Input\InputInterface;
use Symfony\Component\Console\Input\InputOption;
use Symfony\Component\Console\Output\OutputInterface;

/**
 * Long-running scheduler worker that executes periodic tasks in-process.
 *
 * Runs as a dedicated Docker service. Each task has a configured interval;
 * the worker ticks every 30 seconds and fires any task whose interval has
 * elapsed since its last execution.
 *
 * Use --once to execute a single cycle (all tasks) and exit — useful for
 * testing and dev verification.
 */
#[AsCommand(
    name: 'app:scheduler:run',
    description: 'Run the continuous scheduler worker (Option A: loop-based)',
)]
class SchedulerWorkerCommand extends Command
{
    /** Seconds between scheduler ticks. */
    private const TICK_INTERVAL = 30;

    public function __construct(
        private readonly BookingHoldService $holdService,
        private readonly BillingService $billingService,
        private readonly ReconciliationService $reconciliationService,
        private readonly NotificationService $notificationService,
        private readonly BookingService $bookingService,
        private readonly IdempotencyService $idempotencyService,
        private readonly BackupService $backupService,
        private readonly UserRepository $userRepository,
    ) {
        parent::__construct();
    }

    protected function configure(): void
    {
        $this->addOption('once', null, InputOption::VALUE_NONE, 'Run one full cycle and exit (test/dev mode)');
    }

    /**
     * Returns the schedule table: [task_name => [callable, interval_seconds]].
     *
     * @return array<string, array{callable: callable, interval: int}>
     */
    public function getSchedule(): array
    {
        return [
            'expire_holds' => [
                'callable' => fn () => $this->holdService->expireHolds(),
                'interval' => 60,
            ],
            'deliver_notifications' => [
                'callable' => fn () => $this->notificationService->deliverPendingNotifications(),
                'interval' => 60,
            ],
            'evaluate_no_shows' => [
                'callable' => fn () => $this->bookingService->evaluateNoShows(),
                'interval' => 300, // 5 minutes
            ],
            'generate_recurring_bills' => [
                'callable' => fn () => $this->billingService->generateRecurringBills(),
                'interval' => 3600, // 1 hour
            ],
            'cleanup_idempotency_keys' => [
                'callable' => fn () => $this->idempotencyService->cleanupExpired(),
                'interval' => 3600,
            ],
            'run_reconciliation' => [
                'callable' => fn () => $this->reconciliationService->runDailyReconciliation(),
                'interval' => 86400, // 24 hours
            ],
            'create_backups' => [
                'callable' => fn () => $this->runBackups(),
                'interval' => 86400,
            ],
        ];
    }

    protected function execute(InputInterface $input, OutputInterface $output): int
    {
        $once = (bool) $input->getOption('once');

        $output->writeln(sprintf(
            '<info>[scheduler]</info> Starting%s — tick every %ds, %d tasks registered',
            $once ? ' (once mode)' : '',
            self::TICK_INTERVAL,
            count($this->getSchedule()),
        ));

        // Initialise last-run timestamps so daily tasks don't all fire on first tick.
        // Minute/hourly tasks fire immediately; daily tasks get a grace window.
        $now = time();
        $lastRun = [];
        foreach ($this->getSchedule() as $name => ['interval' => $interval]) {
            if ($interval >= 86400) {
                // Daily tasks: pretend they ran recently so they don't all fire at startup.
                // They'll fire after their full interval elapses.
                $lastRun[$name] = $now;
            } else {
                // Sub-daily tasks: fire on first tick.
                $lastRun[$name] = 0;
            }
        }

        if ($once) {
            $this->runCycle($output, $lastRun, force: true);
            $output->writeln('<info>[scheduler]</info> Single cycle complete — exiting.');
            return Command::SUCCESS;
        }

        // Main loop — runs until the process is killed (SIGTERM from Docker).
        while (true) {
            $this->runCycle($output, $lastRun);
            sleep(self::TICK_INTERVAL);
        }

        // @codeCoverageIgnoreStart
        return Command::SUCCESS;
        // @codeCoverageIgnoreEnd
    }

    /**
     * @param array<string, int> $lastRun Modified in-place with new timestamps.
     */
    private function runCycle(OutputInterface $output, array &$lastRun, bool $force = false): void
    {
        $now = time();

        foreach ($this->getSchedule() as $name => ['callable' => $callable, 'interval' => $interval]) {
            $elapsed = $now - ($lastRun[$name] ?? 0);

            if (!$force && $elapsed < $interval) {
                continue;
            }

            try {
                $result = $callable();
                $lastRun[$name] = time();
                $output->writeln(sprintf(
                    '<info>[scheduler]</info> %s — OK (result: %s)',
                    $name,
                    is_int($result) ? (string) $result : 'done',
                ));
            } catch (\Throwable $e) {
                // Log failure but continue — one task must never bring down the worker.
                $lastRun[$name] = time();
                $output->writeln(sprintf(
                    '<error>[scheduler]</error> %s — FAILED: %s',
                    $name,
                    $e->getMessage(),
                ));
            }
        }
    }

    private function runBackups(): int
    {
        $orgIds = $this->userRepository->findDistinctOrganizationIds();
        $count = 0;

        foreach ($orgIds as $orgId) {
            try {
                $this->backupService->createSystemBackup($orgId);
                $count++;
            } catch (\Throwable) {
                // Per-org isolation — continue with next org.
            }
        }

        return $count;
    }
}
