10	use Symfony\Component\HttpKernel\Event\ExceptionEvent;
11	use Symfony\Component\HttpKernel\KernelEvents;
12	
13	/**
14	 * Records request latency and error metrics into MetricsCollector.
15	 * Priority: runs early on request, late on response/exception.
16	 */
17	class RequestMetricsListener
18	{
19	    private const REQUEST_START_ATTR = '_metrics_start';
20	
21	    public function __construct(private readonly MetricsCollector $collector) {}
22	
23	    #[AsEventListener(event: KernelEvents::REQUEST, priority: 1000)]
24	    public function onRequest(RequestEvent $event): void
25	    {
26	        if (!$event->isMainRequest()) return;
27	        $event->getRequest()->attributes->set(self::REQUEST_START_ATTR, microtime(true));
28	    }
29	
30	    #[AsEventListener(event: KernelEvents::RESPONSE, priority: -1000)]
31	    public function onResponse(ResponseEvent $event): void
32	    {
33	        if (!$event->isMainRequest()) return;
34	        $request = $event->getRequest();
35	        $start = $request->attributes->get(self::REQUEST_START_ATTR);
36	        if ($start === null) return;
37	
38	        $endpoint = $request->getMethod() . ' ' . $request->getPathInfo();
39	        $durationMs = (microtime(true) - $start) * 1000;
40	        $this->collector->recordLatency($endpoint, $durationMs);
41	
42	        $status = $event->getResponse()->getStatusCode();
43	        if ($status >= 400) {
44	            $this->collector->recordError($endpoint, $status);
45	        }
46	    }
47	
48	    #[AsEventListener(event: KernelEvents::EXCEPTION, priority: -1000)]
49	    public function onException(ExceptionEvent $event): void
50	    {
51	        if (!$event->isMainRequest()) return;
52	        $request = $event->getRequest();
53	        $endpoint = $request->getMethod() . ' ' . $request->getPathInfo();
54	        $this->collector->recordError($endpoint, 500);
55	    }
56	}
