    // ═══════════════════════════════════════════════════════════════
    // ISSUE 1 — ENUM VALIDATION (500 → 422)
    // ═══════════════════════════════════════════════════════════════

    public function testInvalidUserRoleReturns422WithAllowedValues(): void
    {
        try {
            EnumValidator::validate('superadmin', UserRole::class, 'role');
            $this->fail('Should throw');
        } catch (InvalidEnumException $e) {
            $arr = $e->toArray();
            $this->assertSame(422, $arr['code']);
            $this->assertSame('invalid_enum', $arr['error']);
            $this->assertSame('role', $arr['field']);
            $this->assertContains('administrator', $arr['allowed_values']);
            $this->assertContains('tenant', $arr['allowed_values']);
            $this->assertContains('property_manager', $arr['allowed_values']);
            $this->assertContains('finance_clerk', $arr['allowed_values']);
        }
    }

    public function testInvalidCapacityModeReturns422(): void
    {
        try {
            EnumValidator::validate('shared_pool', CapacityMode::class, 'capacity_mode');
            $this->fail('Should throw');
        } catch (InvalidEnumException $e) {
            $arr = $e->toArray();
            $this->assertSame('capacity_mode', $arr['field']);
            $this->assertContains('discrete_units', $arr['allowed_values']);
            $this->assertContains('single_slot', $arr['allowed_values']);
        }
    }

    public function testInvalidRateTypeReturns422(): void
    {
        try {
            EnumValidator::validate('weekly', RateType::class, 'rate_type');
            $this->fail('Should throw');
        } catch (InvalidEnumException $e) {
            $arr = $e->toArray();
            $this->assertSame('rate_type', $arr['field']);
            $this->assertContains('hourly', $arr['allowed_values']);
            $this->assertContains('daily', $arr['allowed_values']);
            $this->assertContains('monthly', $arr['allowed_values']);
            $this->assertContains('flat', $arr['allowed_values']);
        }
    }

    public function testValidEnumPassesThrough(): void
    {
        $role = EnumValidator::validate('tenant', UserRole::class, 'role');
        $this->assertSame(UserRole::TENANT, $role);

        $mode = EnumValidator::validate('discrete_units', CapacityMode::class, 'capacity_mode');
        $this->assertSame(CapacityMode::DISCRETE_UNITS, $mode);
    }

    // ═══════════════════════════════════════════════════════════════
    // ISSUE 3 — SCHEDULER VERIFICATION
    // ═══════════════════════════════════════════════════════════════

    private function makeScheduler(): array
    {
        $holdService = $this->createMock(BookingHoldService::class);
        $billingService = $this->createMock(BillingService::class);
        $reconciliationService = $this->createMock(ReconciliationService::class);
        $notificationService = $this->createMock(NotificationService::class);
        $bookingService = $this->createMock(BookingService::class);
        $idempotencyService = $this->createMock(IdempotencyService::class);
        $backupService = $this->createMock(BackupService::class);
        $userRepo = $this->createMock(UserRepository::class);
        $userRepo->method('findDistinctOrganizationIds')->willReturn([]);

        $cmd = new SchedulerWorkerCommand(
            $holdService, $billingService, $reconciliationService,
