    // ISSUE 7 — OBSERVABILITY / METRICS
    // ═══════════════════════════════════════════════════════════════

    public function testMetricsCollectorRecordsLatencyAndErrors(): void
    {
        $collector = new MetricsCollector();

        $collector->recordLatency('POST /api/v1/holds', 45.0);
        $collector->recordLatency('POST /api/v1/holds', 55.0);
        $collector->recordLatency('POST /api/v1/payments/callback', 120.0);
