        $s['billingService']->method('generateRecurringBills')->willReturn(0);
        $s['reconciliationService']->method('runDailyReconciliation')->willReturn(0);
        $s['bookingService']->method('evaluateNoShows')->willReturn(0);
        $s['idempotencyService']->method('cleanupExpired')->willReturn(0);

        $text = $this->runOnce($s['cmd']);

        // Verify scheduler logs identify each task by name (observability)
        $this->assertStringContainsString('[scheduler]', $text);
        $this->assertStringContainsString('expire_holds', $text);
        $this->assertStringContainsString('generate_recurring_bills', $text);
        $this->assertStringContainsString('run_reconciliation', $text);
        $this->assertStringContainsString('deliver_notifications', $text);
