    public function testMetricsCollectorFailedJobCounter(): void
    {
        $collector = new MetricsCollector();

        $this->assertSame(0, $collector->getSummary()['failed_job_count']);

        $collector->incrementFailedJobs();
        $collector->incrementFailedJobs();

        $this->assertSame(2, $collector->getSummary()['failed_job_count']);
    }
