22	 * Long-running scheduler worker that executes periodic tasks in-process.
23	 *
24	 * Runs as a dedicated Docker service. Each task has a configured interval;
25	 * the worker ticks every 30 seconds and fires any task whose interval has
26	 * elapsed since its last execution.
27	 *
28	 * Use --once to execute a single cycle (all tasks) and exit — useful for
29	 * testing and dev verification.
30	 */
31	#[AsCommand(
32	    name: 'app:scheduler:run',
33	    description: 'Run the continuous scheduler worker (Option A: loop-based)',
34	)]
35	class SchedulerWorkerCommand extends Command
36	{
37	    /** Seconds between scheduler ticks. */
38	    private const TICK_INTERVAL = 30;
39	
40	    public function __construct(
41	        private readonly BookingHoldService $holdService,
42	        private readonly BillingService $billingService,
43	        private readonly ReconciliationService $reconciliationService,
44	        private readonly NotificationService $notificationService,
45	        private readonly BookingService $bookingService,
46	        private readonly IdempotencyService $idempotencyService,
47	        private readonly BackupService $backupService,
48	        private readonly UserRepository $userRepository,
49	    ) {
50	        parent::__construct();
51	    }
52	
53	    protected function configure(): void
54	    {
55	        $this->addOption('once', null, InputOption::VALUE_NONE, 'Run one full cycle and exit (test/dev mode)');
56	    }
57	
58	    /**
59	     * Returns the schedule table: [task_name => [callable, interval_seconds]].
60	     *
61	     * @return array<string, array{callable: callable, interval: int}>
62	     */
63	    public function getSchedule(): array
64	    {
65	        return [
66	            'expire_holds' => [
67	                'callable' => fn () => $this->holdService->expireHolds(),
68	                'interval' => 60,
69	            ],
70	            'deliver_notifications' => [
71	                'callable' => fn () => $this->notificationService->deliverPendingNotifications(),
72	                'interval' => 60,
73	            ],
74	            'evaluate_no_shows' => [
75	                'callable' => fn () => $this->bookingService->evaluateNoShows(),
76	                'interval' => 300, // 5 minutes
77	            ],
78	            'generate_recurring_bills' => [
79	                'callable' => fn () => $this->billingService->generateRecurringBills(),
80	                'interval' => 3600, // 1 hour
81	            ],
82	            'cleanup_idempotency_keys' => [
83	                'callable' => fn () => $this->idempotencyService->cleanupExpired(),
84	                'interval' => 3600,
85	            ],
86	            'run_reconciliation' => [
87	                'callable' => fn () => $this->reconciliationService->runDailyReconciliation(),
88	                'interval' => 86400, // 24 hours
89	            ],
90	            'create_backups' => [
91	                'callable' => fn () => $this->runBackups(),
92	                'interval' => 86400,
93	            ],
94	        ];
95	    }
96	
97	    protected function execute(InputInterface $input, OutputInterface $output): int
98	    {
99	        $once = (bool) $input->getOption('once');
100	
101	        $output->writeln(sprintf(
102	            '<info>[scheduler]</info> Starting%s — tick every %ds, %d tasks registered',
103	            $once ? ' (once mode)' : '',
104	            self::TICK_INTERVAL,
105	            count($this->getSchedule()),
106	        ));
107	
108	        // Initialise last-run timestamps so daily tasks don't all fire on first tick.
109	        // Minute/hourly tasks fire immediately; daily tasks get a grace window.
110	        $now = time();
111	        $lastRun = [];
112	        foreach ($this->getSchedule() as $name => ['interval' => $interval]) {
113	            if ($interval >= 86400) {
114	                // Daily tasks: pretend they ran recently so they don't all fire at startup.
115	                // They'll fire after their full interval elapses.
116	                $lastRun[$name] = $now;
117	            } else {
118	                // Sub-daily tasks: fire on first tick.
119	                $lastRun[$name] = 0;
120	            }
121	        }
122	
123	        if ($once) {
124	            $this->runCycle($output, $lastRun, force: true);
125	            $output->writeln('<info>[scheduler]</info> Single cycle complete — exiting.');
126	            return Command::SUCCESS;
127	        }
128	
129	        // Main loop — runs until the process is killed (SIGTERM from Docker).
130	        while (true) {
131	            $this->runCycle($output, $lastRun);
132	            sleep(self::TICK_INTERVAL);
133	        }
134	
135	        // @codeCoverageIgnoreStart
136	        return Command::SUCCESS;
137	        // @codeCoverageIgnoreEnd
138	    }
139	
140	    /**
141	     * @param array<string, int> $lastRun Modified in-place with new timestamps.
142	     */
143	    private function runCycle(OutputInterface $output, array &$lastRun, bool $force = false): void
144	    {
145	        $now = time();
146	
147	        foreach ($this->getSchedule() as $name => ['callable' => $callable, 'interval' => $interval]) {
148	            $elapsed = $now - ($lastRun[$name] ?? 0);
149	
150	            if (!$force && $elapsed < $interval) {
151	                continue;
152	            }
153	
154	            try {
155	                $result = $callable();
156	                $lastRun[$name] = time();
157	                $output->writeln(sprintf(
158	                    '<info>[scheduler]</info> %s — OK (result: %s)',
159	                    $name,
160	                    is_int($result) ? (string) $result : 'done',
161	                ));
162	            } catch (\Throwable $e) {
163	                // Log failure but continue — one task must never bring down the worker.
164	                $lastRun[$name] = time();
165	                $output->writeln(sprintf(
166	                    '<error>[scheduler]</error> %s — FAILED: %s',
167	                    $name,
168	                    $e->getMessage(),
169	                ));
170	            }
171	        }
172	    }
173	
174	    private function runBackups(): int
175	    {
176	        $orgIds = $this->userRepository->findDistinctOrganizationIds();
177	        $count = 0;
178	
179	        foreach ($orgIds as $orgId) {
180	            try {
181	                $this->backupService->createSystemBackup($orgId);
182	                $count++;
183	            } catch (\Throwable) {
184	                // Per-org isolation — continue with next org.
185	            }
186	        }
187	
188	        return $count;
189	    }
190	}
