11	let failedQueue: Array<{
12	  resolve: (token: string) => void;
13	  reject: (error: unknown) => void;
14	}> = [];
15	
16	function processQueue(error: unknown, token: string | null) {
17	  failedQueue.forEach((promise) => {
18	    if (error) {
19	      promise.reject(error);
20	    } else {
21	      promise.resolve(token!);
22	    }
23	  });
24	  failedQueue = [];
25	}
