27	client.interceptors.request.use((config) => {
28	  const token = localStorage.getItem('access_token');
29	  if (token) {
30	    config.headers.Authorization = `Bearer ${token}`;
31	  }
32	  return config;
33	});
34	
35	// Unwrap backend {data: ...} wrapper so API functions receive the payload directly
36	client.interceptors.response.use(
37	  (response) => {
38	    if (response.data && typeof response.data === 'object' && 'data' in response.data && !('meta' in response.data)) {
39	      response.data = response.data.data;
40	    }
41	    return response;
42	  },
43	  async (error) => {
44	    const originalRequest = error.config;
45	
46	    if (error.response?.status !== 401 || originalRequest._retry) {
47	      return Promise.reject(error);
48	    }
49	
50	    if (isRefreshing) {
51	      return new Promise<string>((resolve, reject) => {
52	        failedQueue.push({ resolve, reject });
53	      }).then((token) => {
54	        originalRequest.headers.Authorization = `Bearer ${token}`;
55	        return client(originalRequest);
56	      });
57	    }
