59	    originalRequest._retry = true;
60	    isRefreshing = true;
61	
62	    const refreshToken = localStorage.getItem('refresh_token');
63	
64	    if (!refreshToken) {
65	      isRefreshing = false;
66	      localStorage.removeItem('access_token');
67	      localStorage.removeItem('refresh_token');
68	      window.location.href = '/login';
69	      return Promise.reject(error);
70	    }
71	
72	    try {
73	      const { data: responseBody } = await axios.post('/api/v1/auth/refresh', {
74	        refresh_token: refreshToken,
75	      });
76	
77	      const newAccessToken: string = responseBody.data?.access_token ?? responseBody.access_token;
