declare(strict_types=1);

namespace App\Security;

use App\Repository\UserRepository;
use Symfony\Component\HttpFoundation\JsonResponse;
use Symfony\Component\HttpFoundation\Request;
use Symfony\Component\HttpFoundation\Response;
use Symfony\Component\Security\Core\Authentication\Token\TokenInterface;
use Symfony\Component\Security\Core\Exception\AuthenticationException;
use Symfony\Component\Security\Http\Authenticator\AbstractAuthenticator;
use Symfony\Component\Security\Http\Authenticator\Passport\Badge\UserBadge;
use Symfony\Component\Security\Http\Authenticator\Passport\Passport;
use Symfony\Component\Security\Http\Authenticator\Passport\SelfValidatingPassport;

/**
 * Framework-level authenticator that plugs into Symfony's security firewall.
 *
 * This authenticator runs for all /api/ routes except PUBLIC_ROUTES.
 * It delegates JWT parsing to JwtTokenManager and user lookup to UserRepository.
 * The existing JwtAuthenticator event listener is retained as supplemental
 * defense-in-depth (it sets the authenticated_user request attribute that
 * controllers consume).
 */
class ApiTokenAuthenticator extends AbstractAuthenticator
{
    private const PUBLIC_ROUTES = [
        '/api/v1/health',
        '/api/v1/bootstrap',
        '/api/v1/auth/login',
        '/api/v1/auth/refresh',
        '/api/v1/payments/callback',
    ];

    public function __construct(
        private readonly JwtTokenManager $jwtTokenManager,
        private readonly UserRepository $userRepository,
    ) {}

    public function supports(Request $request): ?bool
    {
        $path = $request->getPathInfo();

        // Public routes: explicitly skip authentication
        foreach (self::PUBLIC_ROUTES as $publicRoute) {
            if ($path === $publicRoute) {
                return false;
            }
        }

        // Only authenticate /api/ routes
        return str_starts_with($path, '/api/');
    }

    public function authenticate(Request $request): Passport
    {
        $authHeader = $request->headers->get('Authorization', '');

        if (!str_starts_with($authHeader, 'Bearer ')) {
            throw new AuthenticationException('Missing or invalid Authorization header');
        }

        $jwt = substr($authHeader, 7);

        try {
            $claims = $this->jwtTokenManager->parseAccessToken($jwt);
        } catch (\Throwable) {
            throw new AuthenticationException('Invalid or expired token');
        }

        $userId = $claims['user_id'] ?? null;
        if ($userId === null) {
            throw new AuthenticationException('Invalid token claims');
        }

        return new SelfValidatingPassport(
            new UserBadge($userId, function (string $id) use ($claims) {
                $user = $this->userRepository->find($id);

                if ($user === null || !$user->isActive() || $user->isFrozen()) {
                    throw new AuthenticationException(
                        $user !== null && $user->isFrozen()
                            ? 'Account is frozen'
                            : 'User not found or inactive'
                    );
                }

                // Reject tokens issued before password change
                $tokenIssuedAt = $claims['issued_at'] ?? null;
                $passwordChangedAt = $user->getPasswordChangedAt();
                if ($tokenIssuedAt instanceof \DateTimeImmutable && $passwordChangedAt !== null) {
                    if ($tokenIssuedAt < $passwordChangedAt) {
                        throw new AuthenticationException('Token invalidated by password change');
                    }
                }

                return $user;
            }),
        );
    }

    public function onAuthenticationSuccess(Request $request, TokenInterface $token, string $firewallName): ?Response
    {
        // Let the request continue — the JwtAuthenticator listener sets
        // authenticated_user on the request attributes for controller use.
        return null;
    }

    public function onAuthenticationFailure(Request $request, AuthenticationException $exception): ?Response
    {
        return new JsonResponse([
            'code' => 401,
            'message' => $exception->getMessage(),
            'details' => null,
        ], 401);
    }
}
"}

