declare(strict_types=1);

namespace App\Tests\Unit\Security;

use App\Entity\Organization;
use App\Entity\User;
use App\Enum\UserRole;
use App\Exception\AccessDeniedException;
use App\Exception\PaymentValidationException;
use App\Repository\UserRepository;
use App\Security\ApiTokenAuthenticator;
use App\Security\JwtAuthenticator;
use App\Security\JwtTokenManager;
use App\Security\RbacEnforcer;
use PHPUnit\Framework\MockObject\MockObject;
use PHPUnit\Framework\TestCase;
use Symfony\Component\HttpFoundation\Request;
use Symfony\Component\HttpKernel\Event\RequestEvent;
use Symfony\Component\HttpKernel\HttpKernelInterface;

/**
 * Final acceptance tests:
 *   1. JwtAuthenticator: public routes skip, protected routes require auth
 *   2. ApiTokenAuthenticator: supports() logic matches JwtAuthenticator
 *   3. Password-invalidated tokens are rejected
 *   4. Privileged-route RBAC matrix (backups, metrics, terminals, settings, refunds)
 *   5. Callback mismatch edge cases (already in FinalHardeningTest, extended here)
 */
class FirewallAndCoverageTest extends TestCase
{
    // ═══════════════════════════════════════════════════════════════
    // 1. JwtAuthenticator: public vs protected routes
    // ═══════════════════════════════════════════════════════════════

    private function makeAuthenticatorEvent(string $path, ?string $bearerToken = null): RequestEvent
    {
        $request = Request::create($path, 'GET');
        if ($bearerToken !== null) {
            $request->headers->set('Authorization', "Bearer {$bearerToken}");
        }
        $kernel = $this->createMock(HttpKernelInterface::class);
        return new RequestEvent($kernel, $request, HttpKernelInterface::MAIN_REQUEST);
    }

    private function makeJwtAuthenticator(?User $userToReturn = null): JwtAuthenticator
    {
        $jwtManager = $this->createMock(JwtTokenManager::class);
        $userRepo = $this->createMock(UserRepository::class);

        if ($userToReturn !== null) {
            $jwtManager->method('parseAccessToken')->willReturn([
                'user_id' => $userToReturn->getId(),
                'organization_id' => 'org-1',
                'role' => $userToReturn->getRole()->value,
                'issued_at' => new \DateTimeImmutable(),
            ]);
            $userRepo->method('find')->willReturn($userToReturn);
        } else {
            $jwtManager->method('parseAccessToken')->willThrowException(
                new \App\Exception\AuthenticationException('Invalid token')
            );
        }

        return new JwtAuthenticator($jwtManager, $userRepo);
    }

    private function makeActiveUser(): User&MockObject
    {
        $org = $this->createMock(Organization::class);
        $org->method('getId')->willReturn('org-1');
        $user = $this->createMock(User::class);
        $user->method('getId')->willReturn('user-1');
        $user->method('getRole')->willReturn(UserRole::TENANT);
        $user->method('getOrganization')->willReturn($org);
        $user->method('getOrganizationId')->willReturn('org-1');
        $user->method('isActive')->willReturn(true);
        $user->method('isFrozen')->willReturn(false);
        $user->method('getPasswordChangedAt')->willReturn(null);
        return $user;
    }

    public function testPublicRoutesSkipAuth(): void
    {
        $authenticator = $this->makeJwtAuthenticator();
        $publicRoutes = [
            '/api/v1/health',
            '/api/v1/bootstrap',
            '/api/v1/auth/login',
            '/api/v1/auth/refresh',
            '/api/v1/payments/callback',
        ];

        foreach ($publicRoutes as $route) {
            $event = $this->makeAuthenticatorEvent($route);
            $authenticator($event);
            $this->assertNull($event->getResponse(), "Public route {$route} must not set error response");
        }
    }

    public function testProtectedRouteWithoutTokenReturns401(): void
    {
        $authenticator = $this->makeJwtAuthenticator();
        $event = $this->makeAuthenticatorEvent('/api/v1/bookings');

        $authenticator($event);

        $this->assertNotNull($event->getResponse());
        $this->assertSame(401, $event->getResponse()->getStatusCode());
        $body = json_decode($event->getResponse()->getContent(), true);
        $this->assertSame(401, $body['code']);
    }

    public function testProtectedRouteWithInvalidTokenReturns401(): void
    {
        $authenticator = $this->makeJwtAuthenticator(); // parseAccessToken throws
        $event = $this->makeAuthenticatorEvent('/api/v1/bookings', 'bad.jwt.token');

        $authenticator($event);

        $this->assertNotNull($event->getResponse());
        $this->assertSame(401, $event->getResponse()->getStatusCode());
    }

    public function testProtectedRouteWithValidTokenSetsUser(): void
    {
        $user = $this->makeActiveUser();
        $authenticator = $this->makeJwtAuthenticator($user);
        $event = $this->makeAuthenticatorEvent('/api/v1/bookings', 'valid.jwt.token');

        $authenticator($event);

        $this->assertNull($event->getResponse(), 'Must not set error response for valid token');
        $this->assertSame($user, $event->getRequest()->attributes->get('authenticated_user'));
    }

    public function testNonApiRoutesSkipAuth(): void
    {
        $authenticator = $this->makeJwtAuthenticator();
        $event = $this->makeAuthenticatorEvent('/some-non-api-path');

        $authenticator($event);

        $this->assertNull($event->getResponse(), 'Non-API routes must be skipped');
    }

