        $repo = $this->createMock(UserRepository::class);
        $repo->method('find')->willReturn($user);

        return new JwtAuthenticator($jwt, $repo);
    }

    /**
     * Admin resets another user's password → token issued before reset → 401.
     * The password change sets passwordChangedAt; authenticator compares iat < passwordChangedAt.
     */
    public function testOldTokenRejectedAfterAdminPasswordReset(): void
    {
        // Token issued at 10:00, password reset at 11:00
        $tokenIat = new \DateTimeImmutable('2026-01-15 10:00:00');
        $pwChanged = new \DateTimeImmutable('2026-01-15 11:00:00');

        $auth = $this->buildAuthenticator($tokenIat, $pwChanged);
        $event = $this->makeAuthEvent('/api/v1/bookings', 'old-token');
        $auth($event);

        $this->assertNotNull($event->getResponse());
        $this->assertSame(401, $event->getResponse()->getStatusCode());
        $body = json_decode($event->getResponse()->getContent(), true);
        $this->assertStringContainsString('password change', $body['message']);
    }

    /**
     * Self password change → same result: old token → 401.
     */
    public function testOldTokenRejectedAfterSelfPasswordChange(): void
    {
        // Same mechanism — passwordChangedAt is set by User::setPasswordHash()
        $tokenIat = new \DateTimeImmutable('2026-03-01 08:00:00');
        $pwChanged = new \DateTimeImmutable('2026-03-01 09:30:00');

        $auth = $this->buildAuthenticator($tokenIat, $pwChanged);
        $event = $this->makeAuthEvent('/api/v1/bookings', 'stale-self-token');
        $auth($event);

        $this->assertSame(401, $event->getResponse()->getStatusCode());
    }

    /**
     * Token issued AFTER password change → accepted.
     */
    public function testNewTokenAcceptedAfterPasswordChange(): void
    {
        $tokenIat = new \DateTimeImmutable('2026-01-15 12:00:00');
        $pwChanged = new \DateTimeImmutable('2026-01-15 11:00:00');

        $auth = $this->buildAuthenticator($tokenIat, $pwChanged);
        $event = $this->makeAuthEvent('/api/v1/bookings', 'new-token');
        $auth($event);

        $this->assertNull($event->getResponse(), 'Token issued after password change must be accepted');
    }

    /**
