    /**
     * outstanding = original - (payments - refunds)
     * This invariant must hold for all bill states.
     */
    public function testOutstandingInvariantAfterPartialPayment(): void
    {
        $original = '500.00';
        $payments = '200.00';
        $refunds = '0.00';
        $outstanding = bcsub($original, bcsub($payments, $refunds, 2), 2);

        $this->assertSame('300.00', $outstanding);
        // Invariant: outstanding >= 0
        $this->assertTrue(bccomp($outstanding, '0.00', 2) >= 0);
    }

    public function testOutstandingInvariantAfterFullPaymentAndRefund(): void
    {
        $original = '500.00';
        $payments = '500.00';
        $refunds = '100.00';
        $outstanding = bcsub($original, bcsub($payments, $refunds, 2), 2);

        $this->assertSame('100.00', $outstanding);
        $this->assertTrue(bccomp($outstanding, '0.00', 2) >= 0);
    }

    public function testOutstandingNeverNegative(): void
    {
        // Even if payments exceed original (should not happen, but invariant must hold)
        $original = '100.00';
        $payments = '150.00';
        $refunds = '0.00';
        $raw = bcsub($original, bcsub($payments, $refunds, 2), 2);
        $outstanding = bccomp($raw, '0.00', 2) < 0 ? '0.00' : $raw;

        $this->assertSame('0.00', $outstanding);
    }

    public function testRefundCannotExceedPayments(): void
    {
        // Refunds must be <= total payments
        $payments = '200.00';
        $refunds = '250.00';
        $this->assertTrue(
            bccomp($refunds, $payments, 2) > 0,
            'Refund exceeding payments must be detected',
        );
    }

