        $this->assertSame(0, max(0, 0 - 5 + 1));
        // 4 active, max 5: excess = 4 - 5 + 1 = 0 → 0 revoked
        $this->assertSame(0, max(0, 4 - 5 + 1));
        // 5 active, max 5: excess = 5 - 5 + 1 = 1 → 1 revoked → 4 remain + 1 new = 5
        $this->assertSame(1, max(0, 5 - 5 + 1));
        // 7 active, max 5: excess = 7 - 5 + 1 = 3 → 3 revoked → 4 remain + 1 new = 5
        $this->assertSame(3, max(0, 7 - 5 + 1));
        // 10 active, max 3: excess = 10 - 3 + 1 = 8 → 8 revoked → 2 remain + 1 new = 3
        $this->assertSame(8, max(0, 10 - 3 + 1));
