    // PAYMENT CALLBACK
    // ═══════════════════════════════════════════════════════════════

    public function testPaymentCallbackRejectsInvalidSignature(): void
    {
        $r = $this->api('POST', '/payments/callback', [
            'request_id' => 'nonexistent',
            'signature' => 'bad_sig',
            'status' => 'succeeded',
            'amount' => '100.00',
            'currency' => 'USD',
        ]);
        // Must not return 200 (accept)
        $this->assertNotSame(200, $r['status']);
